class HandlerRegistry:
    """Dynamic registry for message handlers."""

    def __init__(self):
        self._handlers: Dict[str, Type[MessageHandler]] = {}

    def register(self, message_type: str, handler_class: Type[MessageHandler]):
        """Register a handler for a message type."""
        if not issubclass(handler_class, MessageHandler):
            raise TypeError(f"{handler_class} must be a subclass of MessageHandler")
        self._handlers[message_type] = handler_class
        logger.info(f"Registered handler {handler_class.__name__} for message type '{message_type}'")

    def unregister(self, message_type: str):
        """Unregister a handler for a message type."""
        if message_type in self._handlers:
            del self._handlers[message_type]
            logger.info(f"Unregistered handler for message type '{message_type}'")

    def get_handler(self, message_type: str) -> Optional[MessageHandler]:
        """Get an instantiated handler for a message type."""
        handler_class = self._handlers.get(message_type)
        if handler_class:
            return handler_class()
        return None

    def get_registered_types(self):
        return list(self._handlers.keys())


class DeadLetterManager:
    """Manages failed messages that exceed retry limits."""

    def __init__(self, sqs_client, dlq_url: Optional[str] = None):
        self._sqs_client = sqs_client
        self._dlq_url = dlq_url

    def send_to_dlq(self, message: JobMessage, error: str):
        if not self._dlq_url:
            logger.warning(f"No DLQ configured. Dropping failed message {message.message_id}: {error}")
            return

        try:
            dlq_body = {
                'original_message_id': message.message_id,
                'message_type': message.message_type,
                'payload': message.payload,
                'error': error,
                'retry_count': message.retry_count,
                'failed_at': datetime.utcnow().isoformat(),
            }
            self._sqs_client.send_message(
                QueueUrl=self._dlq_url,
                MessageBody=json.dumps(dlq_body),
            )
            logger.info(f"Message {message.message_id} sent to DLQ")
        except ClientError as e:
            logger.error(f"Failed to send message {message.message_id} to DLQ: {e}")


class SQSWorker:
    """Main SQS worker that polls and processes messages."""

    def __init__(
        self,
        queue_url: str,
        region_name: str = 'us-east-1',
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30,
        dlq_url: Optional[str] = None,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        endpoint_url: Optional[str] = None,
    ):
        self._queue_url = queue_url
        self._max_messages = max_messages
        self._wait_time_seconds = wait_time_seconds
        self._visibility_timeout = visibility_timeout
        self._running = False
        self._processed_count = 0
        self._error_count = 0

        # Build boto3 client kwargs
        client_kwargs = {'region_name': region_name}
        if aws_access_key_id and aws_secret_access_key:
            client_kwargs['aws_access_key_id'] = aws_access_key_id
            client_kwargs['aws_secret_access_key'] = aws_secret_access_key
        if endpoint_url:
            client_kwargs['endpoint_url'] = endpoint_url

        self._sqs_client = boto3.client('sqs', **client_kwargs)

        # Initialize handler registry
        self._registry = HandlerRegistry()
        self._register_default_handlers()

        # Initialize DLQ manager
        self._dlq_manager = DeadLetterManager(self._sqs_client, dlq_url)

        # Middleware/hooks
        self._pre_process_hooks = []
        self._post_process_hooks = []

    def _register_default_handlers(self):
        """Register built-in message handlers."""
        self._registry.register('email_notification', EmailNotificationHandler)
        self._registry.register('data_processing', DataProcessingHandler)
        self._registry.register('image_resize', ImageResizeHandler)
        self._registry.register('webhook', WebhookHandler)
        self._registry.register('report_generation', ReportGenerationHandler)

    def register_handler(self, message_type: str, handler_class: Type[MessageHandler]):
        """Register a custom handler for a message type."""
        self._registry.register(message_type, handler_class)

    def add_pre_process_hook(self, hook):
        """Add a hook that runs before message processing."""
        self._pre_process_hooks.append(hook)

    def add_post_process_hook(self, hook):
        """Add a hook that runs after message processing."""
        self._post_process_hooks.append(hook)

    def _poll_messages(self):
        """Poll messages from SQS queue."""
        try:
            response = self._sqs_client.receive_message(
                QueueUrl=self._queue_url,
                MaxNumberOfMessages=self._max_messages,
                WaitTimeSeconds=self._wait_time_seconds,
                VisibilityTimeout=self._visibility_timeout,
                AttributeNames=['All'],
                MessageAttributeNames=['All'],
            )
            return response.get('Messages', [])
        except ClientError as e:
            logger.error(f"Error polling messages from SQS: {e}")
            return []

    def _delete_message(self, receipt_handle: str):
        """Delete a message from the queue after successful processing."""
        try:
            self._sqs_client.delete_message(
                QueueUrl=self._queue_url,
                ReceiptHandle=receipt_handle,
            )
            logger.debug(f"Deleted message with receipt handle: {receipt_handle[:20]}...")
        except ClientError as e:
            logger.error(f"Error deleting message: {e}")

    def _change_message_visibility(self, receipt_handle: str, timeout: int):
        """Change visibility timeout for a message (for retries)."""
        try:
            self._sqs_client.change_message_visibility(
                QueueUrl=self._queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout,
            )
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e}")

    def _requeue_message(self, message: JobMessage):
        """Requeue a message with incremented retry count."""
        try:
            body = {
                'message_type': message.message_type,
                'payload': message.payload,
                'timestamp': message.timestamp,
                'retry_count': message.retry_count + 1,
                'max_retries': message.max_retries,
            }
            # Exponential backoff delay
            delay = min(2 ** message.retry_count * 5, 900)  # Max 15 min
            self._sqs_client.send_message(
                QueueUrl=self._queue_url,
                MessageBody=json.dumps(body),
                DelaySeconds=delay,
            )
            logger.info(
                f"Requeued message {message.message_id} "
                f"(retry {message.retry_count + 1}/{message.max_retries}, delay {delay}s)"
            )
        except ClientError as e:
            logger.error(f"Error requeuing message {message.message_id}: {e}")

    def _process_message(self, sqs_message: Dict):
        """Process a single SQS message."""
        try:
            message = JobMessage.from_sqs_message(sqs_message)
        except (json.JSONDecodeError, KeyError) as e:
            logger.error(f"Failed to parse message: {e}. Raw body: {sqs_message.get('Body', '')}")
            # Delete malformed messages so they don't loop
            self._delete_message(sqs_message['ReceiptHandle'])
            self._error_count += 1
            return

        logger.info(
            f"Processing message {message.message_id} "
            f"(type: {message.message_type}, retry: {message.retry_count})"
        )

        # Run pre-process hooks
        for hook in self._pre_process_hooks:
            try:
                hook(message)
            except Exception as e:
                logger.warning(f"Pre-process hook failed: {e}")

        # Get handler
        handler = self._registry.get_handler(message.message_type)
        if handler is None:
            logger.error(
                f"No handler registered for message type '{message.message_type}'. "
                f"Registered types: {self._registry.get_registered_types()}"
            )
            self._dlq_manager.send_to_dlq(message, f"No handler for type: {message.message_type}")
            self._delete_message(message.receipt_handle)
            self._error_count += 1
            return

        # Execute handler
        success = False
        error_msg = None
        try:
            success = handler.handle(message)
        except Exception as e:
            error_msg = str(e)
            logger.exception(f"Handler raised exception for message {message.message_id}: {e}")

        if success:
            self._delete_message(message.receipt_handle)
            self._processed_count += 1
            logger.info(f"Message {message.message_id} processed successfully")
        else:
            error_msg = error_msg or "Handler returned False"
            if message.retry_count < message.max_retries:
                # Delete original and requeue with retry count
                self._delete_message(message.receipt_handle)
                self._requeue_message(message)
            else:
                logger.error(
                    f"Message {message.message_id} exceeded max retries ({message.max_retries})"
                )
                self._dlq_manager.send_to_dlq(message, error_msg)
                self._delete_message(message.receipt_handle)
                self._error_count += 1

        # Run post-process hooks
        for hook in self._post_process_hooks:
            try:
                hook(message, success)
            except Exception as e:
                logger.warning(f"Post-process hook failed: {e}")

    def start(self):
        """Start the worker polling loop."""
        self._running = True
        logger.info(
            f"SQS Worker started. Polling queue: {self._queue_url}. "
            f"Registered handlers: {self._registry.get_registered_types()}"
        )

        while self._running:
            try:
                messages = self._poll_messages()

                if not messages:
                    logger.debug("No messages received, continuing to poll...")
                    continue

                logger.info(f"Received {len(messages)} messages")

                for sqs_message in messages:
                    if not self._running:
                        break
                    self._process_message(sqs_message)

            except KeyboardInterrupt:
                logger.info("Keyboard interrupt received")
                self.stop()
            except Exception as e:
                logger.exception(f"Unexpected error in polling loop: {e}")
                time.sleep(5)  # Back off on unexpected errors

        logger.info(
            f"SQS Worker stopped. Processed: {self._processed_count}, Errors: {self._error_count}"
        )

    def stop(self):
        """Gracefully stop the worker."""
        logger.info("Stopping SQS Worker...")
        self._running = False

    @property
    def stats(self):
        return {
            'processed': self._processed_count,
            'errors': self._error_count,
            'running': self._running,
        }


